import{_ as e,p as a,q as t,a1 as c}from"./framework-5866ffd3.js";const d={},r=c('<h1 id="_7、特性的范围和优先级" tabindex="-1"><a class="header-anchor" href="#_7、特性的范围和优先级" aria-hidden="true">#</a> 7、特性的范围和优先级</h1><h2 id="_7-1-特性的范围" tabindex="-1"><a class="header-anchor" href="#_7-1-特性的范围" aria-hidden="true">#</a> 7.1 特性的范围</h2><p>有些特性比如<code>[Header]</code>，可以修饰于接口、方法和参数，使用不同的构造器和修饰于不同的地方产生的含义和结果是有点差别的：</p><p>修饰接口时，表示接口下的所有方法在请求前都会添加这个请求头； 修饰方法时，表示此方法在请求前添加这个请求头； 修饰参数时，表示参数的值将做为请求头的值，由调用者动态传入；</p><h2 id="_7-2-特性的优先级" tabindex="-1"><a class="header-anchor" href="#_7-2-特性的优先级" aria-hidden="true">#</a> 7.2 特性的优先级</h2><p>方法级比接口级优先级高； <code>AllowMultiple</code>为<code>true</code>时，方法级和接口级都生效； <code>AllowMultiple</code>为<code>false</code>时，方法级的生效，接口级的无效；</p>',6),o=[r];function i(s,h){return a(),t("div",null,o)}const _=e(d,[["render",i],["__file","attribute-scope-features.html.vue"]]);export{_ as default};
